import{_ as e,c as t,ag as s,o as n}from"./chunks/framework.mHuDn-wg.js";const h=JSON.parse('{"title":"退火","description":"","frontmatter":{},"headers":[],"relativePath":"分子模拟/必备技能/模拟退火.md","filePath":"分子模拟/必备技能/模拟退火.md","lastUpdated":null}'),r={name:"分子模拟/必备技能/模拟退火.md"};function l(i,a,o,p,d,c){return n(),t("div",null,a[0]||(a[0]=[s('<h1 id="退火" tabindex="-1">退火 <a class="header-anchor" href="#退火" aria-label="Permalink to &quot;退火&quot;">​</a></h1><p>模拟退火算法（Simulated Annealing，SA）是一种优化算法，用于在解空间中寻找最优解或接近最优解的方法。它的名称来源于固体退火过程，其中物质被加热然后逐渐冷却以达到一种均匀有序的状态。模拟退火算法的核心思想是通过模拟这个物理过程来搜索解空间，并且以一定的概率接受较差的解，以避免陷入局部最小值。 在分子动力学模拟中，淬火过程通常涉及将系统加热到高温，然后迅速降低温度以防止相变或晶粒生长。这一过程可以通过分子动力学（MD）模拟实现，其中系统在高温下达到无序状态，然后通过能量优化找到低能构象。例如，通过设置高温下的MD模拟，使分子能够跨越势能面的势垒，然后在低温下进行能量优化，从而找到能量最小的构象。这种方法可以有效地找到系统的局部极小点。在分子模拟中，回火过程可以通过模拟材料在一定温度下的相变动力学来实现。 注意：回火过程中引入的极高温度只是将无序引入聚合物体系的一种常用建模技巧。实际上，纤维素在 500 K 以下碳化。 采用NVT系综进行回火-淬火程序： 在 10 ns 内从 300 K 增加到 1100 K 在 1100 K 高温下再保持 10 ns 在 2 ns 内将加热的结构淬火至 300 K</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span></code></pre></div><p><a href="https://blog.csdn.net/wnm23/article/details/142057181" target="_blank" rel="noreferrer">模拟退火</a></p>',4)]))}const m=e(r,[["render",l]]);export{h as __pageData,m as default};
